-- Empty by default. Idempotent.
-- ============================================================================

CREATE TABLE IF NOT EXISTS webhook_failures (
  id           UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  webhook_type TEXT,                                 -- e.g. 'ghl', 'notification'
