-- [migration]  009_bonzah_integration.sql
-- ═══════════════════════════════════════════════════════════════════════
-- ============================================================
-- Migration 009: Bonzah Insurance Integration — Phase 1 Foundation
-- Annie's Car Rental
--
-- Adds:
--   1. Per-booking Bonzah columns (quote, policy, premium, markup, coverage, sync state)
--   2. bonzah_events audit table — every API call logged
--   3. settings k/v table — runtime-toggleable config (markup %, tier defs, kill switch)
--
-- Safe to re-run. Historical booking data is NOT altered.
-- bonzah_policy_id already exists from 001_initial_schema.sql — preserved unchanged.
-- ============================================================

-- ────────────────────────────────────────────────────────────
-- 1. Bonzah-specific booking columns
-- ────────────────────────────────────────────────────────────
ALTER TABLE bookings
  -- The selected tier (essential | standard | complete) — references settings.bonzah_tiers[].id
  ADD COLUMN IF NOT EXISTS bonzah_tier_id TEXT,

  -- Bonzah-issued draft quote ID (returned from POST /Bonzah/quote with finalize:0)
  ADD COLUMN IF NOT EXISTS bonzah_quote_id TEXT,

  -- Human-readable policy number (e.g., BORD2024092401000009) — set after bind succeeds
  ADD COLUMN IF NOT EXISTS bonzah_policy_no TEXT,

  -- Money: tracked in cents to avoid float drift. premium = Bonzah's quote, markup = our cut.
  ADD COLUMN IF NOT EXISTS bonzah_premium_cents INTEGER,
  ADD COLUMN IF NOT EXISTS bonzah_markup_cents INTEGER,
  ADD COLUMN IF NOT EXISTS bonzah_total_charged_cents INTEGER,

  -- Snapshot of coverage selection + limits + deductibles at quote time (for dashboard display)
  ADD COLUMN IF NOT EXISTS bonzah_coverage_json JSONB,

  -- Internal 24h re-quote cutoff (Bonzah quotes never expire; we enforce a freshness window)
  ADD COLUMN IF NOT EXISTS bonzah_quote_expires_at TIMESTAMPTZ,

  -- Last successful poll against /Bonzah/policy — surfaced in admin "Last synced" widget
  ADD COLUMN IF NOT EXISTS bonzah_last_synced_at TIMESTAMPTZ;

-- Note: bonzah_policy_id VARCHAR(100) already exists from 001_initial_schema.sql

-- Index for the polling job's WHERE clause (active policies, recent trips).
-- Uses return_date (the bookings trip-end column); the polling job filters
-- `.gte('return_date', …)`. ("trip_end_date" is only a Bonzah API payload field.)
CREATE INDEX IF NOT EXISTS idx_bookings_bonzah_policy_active
  ON bookings (insurance_status, return_date)
  WHERE bonzah_policy_id IS NOT NULL;

-- ────────────────────────────────────────────────────────────
-- 2. bonzah_events — audit log of every Bonzah API interaction
-- ────────────────────────────────────────────────────────────
-- Every call to backend/utils/bonzah.js writes one row here. Used for:
--   - Debugging failed binds (request_json + response_json)
--   - Admin Settings page "Recent activity" table
--   - SLA / error-rate dashboards
CREATE TABLE IF NOT EXISTS bonzah_events (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  booking_id UUID REFERENCES bookings(id) ON DELETE SET NULL,
  event_type TEXT NOT NULL,           -- 'auth' | 'quote' | 'bind' | 'policy_get' | 'cancel' | 'extend' | 'epayment' | 'health' | 'poll'
  request_json JSONB,                  -- Outbound payload (with secrets redacted)
  response_json JSONB,                 -- Bonzah's full response body
  status_code INTEGER,                 -- HTTP status
  duration_ms INTEGER,                 -- Round-trip time
  error_text TEXT,                     -- Populated when Bonzah returns data.status !== 0 OR HTTP fails
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_bonzah_events_booking ON bonzah_events (booking_id, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_bonzah_events_recent ON bonzah_events (created_at DESC);
CREATE INDEX IF NOT EXISTS idx_bonzah_events_errors ON bonzah_events (created_at DESC) WHERE error_text IS NOT NULL;

-- ────────────────────────────────────────────────────────────
-- 3. settings — generic key/value runtime config
-- ────────────────────────────────────────────────────────────
-- Used for any feature flag or tunable that should be admin-editable
-- without a redeploy. Bonzah is the first consumer; future features
-- (e.g., other integrations, rate caps) can reuse this table.
CREATE TABLE IF NOT EXISTS settings (
  key TEXT PRIMARY KEY,
  value JSONB NOT NULL,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_by UUID                       -- nullable; set by dashboard SettingsPage when an admin edits
);

-- Auto-update updated_at on row change
CREATE OR REPLACE FUNCTION settings_set_updated_at()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS settings_updated_at ON settings;
CREATE TRIGGER settings_updated_at
  BEFORE UPDATE ON settings
  FOR EACH ROW EXECUTE FUNCTION settings_set_updated_at();

-- ────────────────────────────────────────────────────────────
-- 4. Seed Bonzah default settings (kill switch off, sane defaults)
-- ────────────────────────────────────────────────────────────
-- bonzah_enabled: master kill switch. When false, customer wizard hides Bonzah entirely.
INSERT INTO settings (key, value) VALUES ('bonzah_enabled', 'false'::jsonb)
  ON CONFLICT (key) DO NOTHING;

-- bonzah_markup_percent: percent added to Bonzah's base premium before charging customer.
INSERT INTO settings (key, value) VALUES ('bonzah_markup_percent', '10'::jsonb)
  ON CONFLICT (key) DO NOTHING;

-- bonzah_tiers: tier definitions exposed in the customer wizard.
-- CDW is mandatory floor (renter requirement). Standard pre-selected.
-- Complete auto-hides when pickup state ∈ bonzah_pai_excluded_states.
INSERT INTO settings (key, value) VALUES ('bonzah_tiers',
  '[
    {"id": "essential", "label": "Essential",  "coverages": ["cdw"],                             "default": false, "recommended": false},
    {"id": "standard",  "label": "Standard",   "coverages": ["cdw", "rcli", "sli"],              "default": true,  "recommended": true},
    {"id": "complete",  "label": "Complete",   "coverages": ["cdw", "rcli", "sli", "pai"],       "default": false, "recommended": false}
  ]'::jsonb)
  ON CONFLICT (key) DO NOTHING;

-- bonzah_pai_excluded_states: states where PAI cannot be sold. Populate from Bonzah support before prod.
INSERT INTO settings (key, value) VALUES ('bonzah_pai_excluded_states', '[]'::jsonb)
  ON CONFLICT (key) DO NOTHING;

-- bonzah_excluded_states: states where Bonzah is not offered AT ALL (regulatory).
-- Confirmed by brandon@bonzah.com on 2026-05-01: Michigan, New York, Pennsylvania.
-- These states are absent from the /Bonzah/master US states list — Bonzah cannot bind here.
-- When pickup_state ∈ this list, customer wizard hides the Bonzah path entirely
-- and falls back to the "Use my own insurance" form.
INSERT INTO settings (key, value) VALUES ('bonzah_excluded_states', '["Michigan","New York","Pennsylvania"]'::jsonb)
  ON CONFLICT (key) DO NOTHING;


-- ═══════════════════════════════════════════════════════════════════════
-- [migration]  010_terminal_return_date_invariant.sql
-- ═══════════════════════════════════════════════════════════════════════
-- Migration 010 — Prevent ghost-blocked vehicles
--
-- Bug: a booking could reach status 'returned' or 'completed' while its
-- return_date was still in the future (early return path didn't clamp the
-- date, /complete didn't either). The availability check then treated the
-- terminal row as still occupying the calendar, producing 409 "Those dates
-- are no longer available" on a vehicle that was physically back on the lot.
--
-- This migration:
--   (1) Backfills every existing 'returned'/'completed' booking whose
--       return_date is past today, clamping return_date to the actual
--       return day (actual_return_at::date if present, else today).
--   (2) Adds a CHECK constraint so no future code path, manual SQL, or
--       import script can re-introduce the invariant violation.

BEGIN;

-- (1) Backfill. Surface what's about to change for the audit trail.
WITH offenders AS (
  SELECT
    id,
    booking_code,
    status,
    return_date AS old_return_date,
    COALESCE(actual_return_at::date, CURRENT_DATE) AS new_return_date
  FROM bookings
  WHERE status IN ('returned', 'completed')
    AND return_date > COALESCE(actual_return_at::date, CURRENT_DATE)
),
updated AS (
  UPDATE bookings b
     SET return_date = o.new_return_date
    FROM offenders o
   WHERE b.id = o.id
  RETURNING b.id, o.booking_code, o.status, o.old_return_date, b.return_date AS new_return_date
)
INSERT INTO booking_status_log (booking_id, from_status, to_status, changed_by, reason)
SELECT
  id,
  status,
  status,
  'system_migration_010',
  format(
    'Backfill: clamped return_date %s → %s to repair ghost-blocked calendar',
    old_return_date, new_return_date
  )
FROM updated;

-- (2) Constraint. The invariant is now enforced by the database itself.
ALTER TABLE bookings
  ADD CONSTRAINT bookings_terminal_return_date_not_future
  CHECK (
    status NOT IN ('returned', 'completed')
    OR return_date <= COALESCE(actual_return_at::date, CURRENT_DATE)
  );

COMMIT;


-- ═══════════════════════════════════════════════════════════════════════
-- [migration]  011_checkout_override.sql
-- ═══════════════════════════════════════════════════════════════════════
-- Migration 011 — Checkout override audit columns
--
-- Admins should not be able to start the checkout flow until the renter has
-- self-checked-out via the customer portal (record_type='customer_checkout')
-- or the booking has organically reached status='returned'. When neither has
-- happened (vehicle physically back but customer never tapped "End trip" in
-- the portal), an admin may force-unlock checkout by selecting an override
-- reason. These columns persist that override for audit.
--
-- The override path also synthesizes a customer_checkout record (so the same
-- gate/UI logic that reads checkin_records keeps working downstream) and
-- stamps actual_return_at if it's null. Migration 010's terminal-return-date
-- invariant is preserved: any subsequent transition to 'returned'/'completed'
-- will continue to clamp return_date as needed.

BEGIN;

ALTER TABLE bookings
  ADD COLUMN IF NOT EXISTS checkout_override_reason TEXT,
  ADD COLUMN IF NOT EXISTS checkout_override_note   TEXT,
  ADD COLUMN IF NOT EXISTS checkout_override_by     TEXT,
  ADD COLUMN IF NOT EXISTS checkout_override_at     TIMESTAMPTZ,
  ADD COLUMN IF NOT EXISTS created_by_admin         BOOLEAN NOT NULL DEFAULT FALSE;

COMMENT ON COLUMN bookings.checkout_override_reason IS
  'One of: vehicle_returned_system_not_updated, renter_unreachable_or_abandoned, manual_reconciliation_after_incident, other';
COMMENT ON COLUMN bookings.checkout_override_note IS
  'Free-text note. Required when checkout_override_reason = ''other''.';
COMMENT ON COLUMN bookings.created_by_admin IS
  'TRUE when an admin created this booking on behalf of a customer via the dashboard New Booking modal. Used to auto-approve on payment success (the admin already vetted the request).';

COMMIT;


-- ═══════════════════════════════════════════════════════════════════════
-- [migration]  012_notification_log.sql
-- ═══════════════════════════════════════════════════════════════════════
-- ============================================================================
-- Migration 012 — notification idempotency log
-- ============================================================================
-- Purpose: prevent double-fire of automated notifications when crons retry,
-- get manually replayed, or run after redeploy. Phase 1 audit F-7.
--
-- Before this migration: cron stages (pickup_reminder, return_reminder,
-- late_return_warning, mid_rental_checkin, extension_offer, rental_completed,
-- repeat_customer, late_return_escalation) fire on every cron invocation
-- with no per-booking-per-stage tracking. Manual replays double-text customers.
--
-- After this migration: sendBookingNotification(stage, payload) inserts a row
-- before dispatch. The unique constraint (booking_code, stage, event_date)
-- forces dedup. Duplicate inserts return Postgres 23505 — caller skips.
--
-- Apply via: paste into Supabase SQL Editor, run, verify with the queries
-- at the bottom.
-- ============================================================================

CREATE TABLE IF NOT EXISTS notification_log (
  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  booking_code  TEXT NOT NULL,
  stage         TEXT NOT NULL,
  event_date    DATE NOT NULL DEFAULT CURRENT_DATE,
  sent_at       TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE (booking_code, stage, event_date)
);

CREATE INDEX IF NOT EXISTS idx_notification_log_lookup
  ON notification_log (booking_code, stage, event_date);

-- ── Backfill from existing messages table ───────────────────────────────────
-- Every system notification stored a row in `messages` with
-- metadata = { stage, automated: true, booking_code }. We seed the log from
-- those so the first cron run after deploy doesn't re-fire historical
-- reminders that already went out.
--
-- ON CONFLICT DO NOTHING handles same-day duplicates that may already exist
-- in the messages table (the very bug we're now fixing).

INSERT INTO notification_log (booking_code, stage, event_date, sent_at)
SELECT
  m.metadata->>'booking_code'      AS booking_code,
  m.metadata->>'stage'             AS stage,
  m.created_at::date               AS event_date,
  MIN(m.created_at)                AS sent_at
FROM messages m
WHERE m.metadata->>'automated' = 'true'
  AND COALESCE(m.metadata->>'stage', '')        <> ''
  AND COALESCE(m.metadata->>'booking_code', '') <> ''
GROUP BY
  m.metadata->>'booking_code',
  m.metadata->>'stage',
  m.created_at::date
ON CONFLICT (booking_code, stage, event_date) DO NOTHING;

-- ── Verification queries (run after migration) ──────────────────────────────
--
-- 1. Row count seeded:
--    SELECT COUNT(*) FROM notification_log;
--
-- 2. Spot-check a recent stage:
--    SELECT booking_code, stage, event_date, sent_at
--    FROM notification_log
--    WHERE event_date >= CURRENT_DATE - INTERVAL '7 days'
--    ORDER BY sent_at DESC
--    LIMIT 20;
--
-- 3. Confirm the unique constraint blocks duplicates (should error 23505):
--    INSERT INTO notification_log (booking_code, stage)
--    SELECT booking_code, stage FROM notification_log LIMIT 1;


-- ═══════════════════════════════════════════════════════════════════════
-- [migration]  013_sms_opt_out.sql
-- ═══════════════════════════════════════════════════════════════════════
-- ============================================================================
-- Migration 013 — SMS opt-out tracking (TCPA compliance)
-- ============================================================================
-- Purpose: track customers who replied STOP/UNSUB so the app can short-circuit
-- outbound SMS instead of relying solely on Twilio's carrier-level block.
-- Phase 1 audit F-21.
--
-- Twilio's carrier honors STOP automatically (subsequent messages from your
-- `From` to that customer fail with error 21610), but the app stored no
-- consent state. TCPA compliance for unsolicited marketing
-- (`repeat_customer`, `extension_offer`) requires explicit consent tracking.
-- A future second `From` number, or a future provider migration, would also
-- bypass Twilio's per-number block — making app-level state the safe layer.
--
-- Apply via: paste into Supabase SQL Editor, run, verify with the queries
-- at the bottom.
-- ============================================================================

ALTER TABLE customers
  ADD COLUMN IF NOT EXISTS sms_opt_out BOOLEAN NOT NULL DEFAULT FALSE,
  ADD COLUMN IF NOT EXISTS sms_opt_out_at TIMESTAMPTZ;

CREATE INDEX IF NOT EXISTS idx_customers_sms_opt_out
  ON customers (sms_opt_out)
  WHERE sms_opt_out = TRUE;

-- ── Verification queries ────────────────────────────────────────────────────
--
-- 1. Confirm columns added:
--    SELECT column_name, data_type, is_nullable, column_default
--    FROM information_schema.columns
--    WHERE table_name = 'customers' AND column_name LIKE 'sms_opt_out%';
--
-- 2. All existing customers default to opted-in (no historical consent
--    revocation to backfill — Twilio carrier-level STOPs were never
--    surfaced into the app, so we have no signal to seed from):
--    SELECT COUNT(*) FROM customers WHERE sms_opt_out = TRUE;  -- expect 0


