-- [migration]  014_orphan_stage_cleanup.sql
-- ═══════════════════════════════════════════════════════════════════════
-- ============================================================================
-- Migration 014 — orphan stage cleanup
-- ============================================================================
-- Purpose: drop seeded email_templates rows for stages that the Phase 1 audit
-- (F-4) decided to retire. They were exposed in the dashboard picker UI but
-- had no caller anywhere in code — clicking them did nothing the admin
-- expected.
--
-- Decisions logged in MESSAGING_PHASE1_HANDOFF.md §3 F-4/F-5:
--   - delivery_offer       → DELETE (overlaps booking_submitted's delivery copy)
--   - refund_processed     → DELETE (deposit_refunded already covers this)
--   - inspection_complete  → DELETE (deposit_settled / deposit_refunded carry
--                                    the message — user opted to skip)
--
-- The other orphan stages (damage_notification, day_of_pickup, day_of_return,
-- insurance_policy_issued, insurance_bind_failed, invoice_sent) are kept —
-- the first three are now wired in code, the Bonzah pair is intentionally
-- unwired pending separate decision, and invoice_sent stays as a manual-only
-- template.
--
-- Apply via: paste into Supabase SQL Editor, run, verify with the queries
-- at the bottom.
-- ============================================================================

DELETE FROM email_templates
WHERE stage IN ('delivery_offer', 'refund_processed', 'inspection_complete');

-- ── Verification queries ────────────────────────────────────────────────────
--
-- 1. Confirm the rows are gone (expect 0):
--    SELECT COUNT(*) FROM email_templates
--    WHERE stage IN ('delivery_offer', 'refund_processed', 'inspection_complete');
--
-- 2. Spot-check the remaining stages:
--    SELECT stage, name, is_active FROM email_templates ORDER BY stage;


-- ═══════════════════════════════════════════════════════════════════════
-- [migration]  015_one_active_template_per_stage.sql
-- ═══════════════════════════════════════════════════════════════════════
-- ============================================================================
-- Migration 015 — one active email_template per stage
-- ============================================================================
-- Purpose: prevent the case where two templates share a stage with
-- is_active=true. getRenderedTemplate calls
--   .eq('stage', stage).eq('is_active', true).single()
-- which throws when more than one row matches → falls through to the
-- hardcoded fallback template silently. Phase 1 audit F-18.
--
-- Two-step migration:
--   1. Cleanup any existing duplicates: keep the row with the most recent
--      updated_at (or created_at as tie-breaker) as active, deactivate the rest.
--   2. Add the partial unique index so future inserts/updates are blocked
--      by Postgres at write time.
--
-- Apply via: paste into Supabase SQL Editor, run, verify with the queries
-- at the bottom.
-- ============================================================================

-- ── Step 1: Deactivate older duplicates ────────────────────────────────────
-- For each stage that has multiple is_active=true rows, keep only the
-- most-recently-updated one as active.

WITH ranked AS (
  SELECT
    id,
    ROW_NUMBER() OVER (
      PARTITION BY stage
      ORDER BY updated_at DESC NULLS LAST, created_at DESC NULLS LAST, id DESC
    ) AS rn
  FROM email_templates
  WHERE is_active = TRUE
)
UPDATE email_templates et
SET is_active = FALSE,
    updated_at = COALESCE(et.updated_at, NOW())
FROM ranked r
WHERE et.id = r.id AND r.rn > 1;

-- ── Step 2: Enforce the constraint going forward ────────────────────────────

CREATE UNIQUE INDEX IF NOT EXISTS idx_email_templates_one_active_per_stage
  ON email_templates (stage)
  WHERE is_active = TRUE;

-- ── Verification queries ────────────────────────────────────────────────────
--
-- 1. Confirm at most one active per stage (expect 0 violating rows):
--    SELECT stage, COUNT(*) FROM email_templates
--    WHERE is_active = TRUE
--    GROUP BY stage
--    HAVING COUNT(*) > 1;
--
-- 2. Confirm the index exists:
--    SELECT indexname FROM pg_indexes
--    WHERE tablename = 'email_templates'
--      AND indexname = 'idx_email_templates_one_active_per_stage';
--
-- 3. Confirm the constraint blocks duplicates (should error with 23505):
--    -- Pick a stage that already has an active template and try to activate another:
--    -- INSERT INTO email_templates (stage, name, is_active, subject, body, channel)
--    -- VALUES ('booking_approved', 'Test Dup', true, 's', 'b', 'email');


-- ═══════════════════════════════════════════════════════════════════════
-- [migration]  016_conversation_summaries_view.sql
-- ═══════════════════════════════════════════════════════════════════════
-- ============================================================================
-- Migration 016 — conversation summaries view
-- ============================================================================
-- Purpose: replace the 1000-message scan + JS grouping in
-- GET /messaging/conversations with a server-side DISTINCT ON view.
-- Output is bounded by customer count instead of message volume — won't
-- regress as the messages table grows. Phase 1 audit F-10.
--
-- Apply via: paste into Supabase SQL Editor, run, verify with the queries
-- at the bottom.
-- ============================================================================

CREATE OR REPLACE VIEW v_conversation_summaries AS
SELECT DISTINCT ON (customer_id)
  customer_id,
  body         AS last_message,
  direction    AS last_direction,
  channel      AS last_channel,
  created_at   AS last_at
FROM messages
WHERE customer_id IS NOT NULL
ORDER BY customer_id, created_at DESC;

-- Helpful index if not already present — the existing messages table almost
-- certainly has one, but we add the conditional create just in case.
CREATE INDEX IF NOT EXISTS idx_messages_customer_created
  ON messages (customer_id, created_at DESC);

-- ── Verification queries ────────────────────────────────────────────────────
--
-- 1. Row count — should equal the number of distinct customers with messages:
--    SELECT COUNT(*) FROM v_conversation_summaries;
--    SELECT COUNT(DISTINCT customer_id) FROM messages WHERE customer_id IS NOT NULL;
--    -- These two numbers must match.
--
-- 2. Spot-check a recent conversation:
--    SELECT * FROM v_conversation_summaries
--    ORDER BY last_at DESC LIMIT 5;


-- ═══════════════════════════════════════════════════════════════════════
-- [migration]  017_bouncie_integration.sql
-- ═══════════════════════════════════════════════════════════════════════
-- ============================================================
-- Migration 017: Bouncie Telematics Integration
-- Annie's Car Rental
--
-- Adds the full Bouncie (GPS / OBD-II / trip telemetry) integration:
--   1. bouncie_credentials  — single-row OAuth token store (one Bouncie account per install)
--   2. bouncie_vehicles     — mirror of Bouncie-side vehicles + last-known stats
--   3. bouncie_trips        — trip history from webhooks + /trips polling
--   4. bouncie_events       — audit log of every webhook receipt + REST call
--   5. bouncie_geozones     — admin-managed application geo-zones
--
-- Safe to re-run. No existing data is altered.
-- ============================================================

-- ────────────────────────────────────────────────────────────
-- 1. bouncie_credentials — OAuth tokens (single connected account)
-- ────────────────────────────────────────────────────────────
-- Bouncie's OAuth is per-user. For a small fleet we expect ONE Bouncie
-- account holding every dongle, so we keep a single-row credential
-- store (enforced by the unique partial index below). If we ever need
-- multi-tenant we promote `id` from singleton to an FK on tenant.
CREATE TABLE IF NOT EXISTS bouncie_credentials (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  access_token TEXT NOT NULL,
  refresh_token TEXT NOT NULL,
  token_expires_at TIMESTAMPTZ NOT NULL,
  bouncie_user_email TEXT,
  scopes TEXT,
  connected_by UUID,                              -- admin_profiles.auth_id who clicked Connect
  connected_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Enforce singleton — only one active Bouncie credential row at a time.
-- A NULL `disconnected_at` means active; on disconnect we set it instead of deleting
-- so we keep audit history.
ALTER TABLE bouncie_credentials
  ADD COLUMN IF NOT EXISTS disconnected_at TIMESTAMPTZ;

CREATE UNIQUE INDEX IF NOT EXISTS uq_bouncie_credentials_active
  ON bouncie_credentials ((disconnected_at IS NULL))
  WHERE disconnected_at IS NULL;

-- ────────────────────────────────────────────────────────────
-- 2. bouncie_vehicles — mirror of Bouncie-side vehicles
-- ────────────────────────────────────────────────────────────
-- Key by IMEI (the OBD-II dongle's hardware ID) since VIN can be blank
-- briefly when a dongle is first plugged in. annie_vehicle_id is the FK
-- to our internal fleet; populated automatically by VIN match, manually
-- via the admin "Map" UI if VIN is missing/mismatched.
CREATE TABLE IF NOT EXISTS bouncie_vehicles (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  imei TEXT NOT NULL UNIQUE,
  vin TEXT,
  annie_vehicle_id UUID REFERENCES vehicles(id) ON DELETE SET NULL,

  -- Static metadata from Bouncie
  bouncie_year INTEGER,
  bouncie_make TEXT,
  bouncie_model TEXT,
  bouncie_nickname TEXT,

  -- Last-known live stats (updated by REST poll + tripData webhooks)
  last_lat NUMERIC(10, 7),
  last_lng NUMERIC(10, 7),
  last_heading NUMERIC(5, 2),
  last_speed_mph NUMERIC(6, 2),
  last_address TEXT,
  last_fuel_pct NUMERIC(5, 2),
  last_odometer_miles NUMERIC(10, 2),
  last_engine_running BOOLEAN,
  last_battery_status TEXT,                       -- 'normal' | 'low' | 'critical'
  last_mil_status TEXT,                           -- 'ON' or NULL
  last_dtc_codes TEXT,                            -- comma-sep e.g. "P0420,P0171"

  last_synced_at TIMESTAMPTZ,
  raw_json JSONB,                                 -- full last-seen vehicle payload from Bouncie

  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_bouncie_vehicles_vin ON bouncie_vehicles (vin) WHERE vin IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_bouncie_vehicles_annie ON bouncie_vehicles (annie_vehicle_id) WHERE annie_vehicle_id IS NOT NULL;

-- ────────────────────────────────────────────────────────────
-- 3. bouncie_trips — trip history
-- ────────────────────────────────────────────────────────────
-- One row per Bouncie trip. We capture both ends (start + metrics) and
-- store the gps polyline for replay/analysis. annie_booking_id is set
-- by a join job that finds the booking active during the trip window.
CREATE TABLE IF NOT EXISTS bouncie_trips (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  bouncie_transaction_id TEXT NOT NULL UNIQUE,
  imei TEXT NOT NULL,
  annie_vehicle_id UUID REFERENCES vehicles(id) ON DELETE SET NULL,
  annie_booking_id UUID REFERENCES bookings(id) ON DELETE SET NULL,

  start_at TIMESTAMPTZ,
  end_at TIMESTAMPTZ,
  duration_seconds INTEGER,
  distance_miles NUMERIC(10, 2),
  avg_speed_mph NUMERIC(6, 2),
  max_speed_mph NUMERIC(6, 2),
  fuel_consumed_gallons NUMERIC(8, 3),
  hard_brake_count INTEGER DEFAULT 0,
  hard_accel_count INTEGER DEFAULT 0,

  start_lat NUMERIC(10, 7),
  start_lng NUMERIC(10, 7),
  end_lat NUMERIC(10, 7),
  end_lng NUMERIC(10, 7),
  start_address TEXT,
  end_address TEXT,

  -- Polyline (encoded Google polyline) or GeoJSON LineString — set by /trips REST poll
  gps_polyline TEXT,
  gps_geojson JSONB,

  raw_json JSONB,                                 -- full tripMetrics payload
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_bouncie_trips_vehicle_start ON bouncie_trips (annie_vehicle_id, start_at DESC);
CREATE INDEX IF NOT EXISTS idx_bouncie_trips_booking ON bouncie_trips (annie_booking_id) WHERE annie_booking_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_bouncie_trips_imei_start ON bouncie_trips (imei, start_at DESC);

-- ────────────────────────────────────────────────────────────
-- 4. bouncie_events — audit log of every webhook receipt + REST call
-- ────────────────────────────────────────────────────────────
-- Used for:
--   - Debugging missing/duplicate events (Bouncie warns about tripData duplication on reconnect)
--   - Settings page "Recent activity" feed
--   - Rate / error dashboards
CREATE TABLE IF NOT EXISTS bouncie_events (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  event_type TEXT NOT NULL,                       -- 'connect' | 'disconnect' | 'mil' | 'battery' | 'tripStart' | 'tripData' | 'tripMetrics' | 'tripEnd' | 'vinChange' | 'applicationGeozone' | 'userGeozone' | 'rest_call'
  source TEXT NOT NULL,                           -- 'webhook' | 'rest' | 'poll'
  imei TEXT,
  vin TEXT,
  annie_vehicle_id UUID,
  annie_booking_id UUID,

  payload JSONB,                                  -- inbound webhook body OR outbound REST response
  request_path TEXT,                              -- REST endpoint hit (for source='rest')
  status_code INTEGER,                            -- HTTP status (for source='rest')
  duration_ms INTEGER,
  error_text TEXT,

  received_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  processed_at TIMESTAMPTZ
);

CREATE INDEX IF NOT EXISTS idx_bouncie_events_recent ON bouncie_events (received_at DESC);
CREATE INDEX IF NOT EXISTS idx_bouncie_events_type ON bouncie_events (event_type, received_at DESC);
CREATE INDEX IF NOT EXISTS idx_bouncie_events_imei ON bouncie_events (imei, received_at DESC) WHERE imei IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_bouncie_events_errors ON bouncie_events (received_at DESC) WHERE error_text IS NOT NULL;

-- ────────────────────────────────────────────────────────────
-- 5. bouncie_geozones — admin-managed Application Geo-Zones
-- ────────────────────────────────────────────────────────────
-- Bouncie's geozone model has 3 entities: Location → (optional) Schedule → Geozone.
-- We collapse that into one local row for the admin UI; on save we POST all 3 in sequence.
CREATE TABLE IF NOT EXISTS bouncie_geozones (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL,
  bouncie_location_id TEXT,
  bouncie_schedule_id TEXT,
  bouncie_geozone_id TEXT,

  geometry_type TEXT NOT NULL,                    -- 'circle' | 'polygon'
  center_lat NUMERIC(10, 7),
  center_lng NUMERIC(10, 7),
  radius_meters NUMERIC(10, 2),
  polygon_geojson JSONB,                          -- For polygon geometry

  enabled BOOLEAN NOT NULL DEFAULT true,
  alert_on_enter BOOLEAN NOT NULL DEFAULT false,
  alert_on_exit BOOLEAN NOT NULL DEFAULT true,    -- Default: alert when a rental leaves the zone

  created_by UUID,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_bouncie_geozones_enabled ON bouncie_geozones (enabled) WHERE enabled = true;

-- ────────────────────────────────────────────────────────────
-- 6. bookings — extra columns for telematics-driven mileage
-- ────────────────────────────────────────────────────────────
-- When the customer submits checkout via the portal, we also snapshot
-- Bouncie's current odometer for that vehicle so admin can compare
-- manual vs. telematics reading and catch discrepancies.
ALTER TABLE bookings
  ADD COLUMN IF NOT EXISTS bouncie_pickup_odometer NUMERIC(10, 2),
  ADD COLUMN IF NOT EXISTS bouncie_return_odometer NUMERIC(10, 2),
  ADD COLUMN IF NOT EXISTS bouncie_pickup_at TIMESTAMPTZ,
  ADD COLUMN IF NOT EXISTS bouncie_return_at TIMESTAMPTZ;


-- ═══════════════════════════════════════════════════════════════════════
-- [migration]  018_business_settings.sql
-- ═══════════════════════════════════════════════════════════════════════
-- ============================================================================
-- Migration 018 — business_settings (singleton) + sms_opt_out_log (audit trail)
-- ============================================================================
-- Purpose: support the admin-controlled SMS guardrails introduced in Phase 1.
--
--   1. business_settings — single-row config for quiet hours (start/end/timezone)
--      and quiet-hours policy ('skip' = drop SMS, 'defer' = future enhancement).
--      Singleton enforced by `id = 1` CHECK constraint (matches the pattern used
--      by bouncie_credentials in migration 017).
--
--   2. sms_opt_out_log — append-only audit trail for opt-out / opt-in events
--      so we can show admins who opted a customer back in (and when), and
--      defend against TCPA disputes. Captures: keyword opt-outs (STOP/UNSUB),
--      admin-initiated opt-outs/ins, and customer-portal-initiated events.
--
-- This migration is the foundation for:
--   - notifyService.js#sendSMS — checks quiet hours before calling Twilio
--   - GET/PUT /api/v1/settings/business — admin reads/writes the config
--   - GET /api/v1/customers/sms-opt-outs + POST /api/v1/customers/:id/sms-opt-in
--   - MessagingPage → Opt-Outs tab
--
-- Safe to re-run. No existing data is altered.
-- ============================================================================

-- ────────────────────────────────────────────────────────────────────────────
-- 1. business_settings (singleton)
-- ────────────────────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS business_settings (
  id                    SMALLINT PRIMARY KEY DEFAULT 1 CHECK (id = 1),

  -- SMS quiet hours
  quiet_hours_enabled   BOOLEAN     NOT NULL DEFAULT TRUE,
  quiet_hours_start     TIME        NOT NULL DEFAULT '21:00',
  quiet_hours_end       TIME        NOT NULL DEFAULT '08:00',
  quiet_hours_timezone  TEXT        NOT NULL DEFAULT 'America/New_York',
  quiet_hours_policy    TEXT        NOT NULL DEFAULT 'skip'
    CHECK (quiet_hours_policy IN ('skip','defer')),

  -- Bookkeeping
  updated_at            TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_by            UUID                                 -- staff user_id from last edit
);

-- Seed the singleton row. Idempotent — ON CONFLICT preserves existing values
-- if this migration is re-applied after the admin has tweaked settings.
INSERT INTO business_settings (id) VALUES (1) ON CONFLICT (id) DO NOTHING;

-- ────────────────────────────────────────────────────────────────────────────
-- 2. sms_opt_out_log — append-only audit trail
-- ────────────────────────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS sms_opt_out_log (
  id           UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  customer_id  UUID NOT NULL REFERENCES customers(id) ON DELETE CASCADE,
  action       TEXT NOT NULL CHECK (action IN ('opt_out','opt_in')),
  source       TEXT NOT NULL CHECK (source IN ('keyword','admin','customer_portal','backfill')),
  actor_id     UUID,                                          -- staff user_id when source='admin'
  note         TEXT,                                          -- e.g. "Customer called and asked back in"
  created_at   TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_sms_opt_out_log_customer
  ON sms_opt_out_log (customer_id, created_at DESC);

-- ────────────────────────────────────────────────────────────────────────────
-- 3. Backfill: every currently-opted-out customer gets a single 'backfill'
--    row so the admin view shows a sensible date for historical opt-outs.
--    Skips customers that already have a log row (idempotent re-run safety).
-- ────────────────────────────────────────────────────────────────────────────
INSERT INTO sms_opt_out_log (customer_id, action, source, note, created_at)
SELECT
  c.id,
  'opt_out',
  'backfill',
  'Pre-existing opt-out (no historical event captured)',
  COALESCE(c.sms_opt_out_at, now())
FROM customers c
WHERE c.sms_opt_out = TRUE
  AND NOT EXISTS (
    SELECT 1 FROM sms_opt_out_log l
    WHERE l.customer_id = c.id
  );

-- ────────────────────────────────────────────────────────────────────────────
-- Verification queries (run manually in the SQL Editor after applying)
-- ────────────────────────────────────────────────────────────────────────────
--
